      <span v-if="layer.clippingMask" class="layer-clip-chip" title="\u5DF2\u526A\u88C1\u5230\u4E0B\u65B9\u7B2C\u4E00\u9897\u975E\u526A\u88C1\u5C42">\u2198</span>
